### 3. 无认证和授权机制 (CVSS: 8.2)

**位置**: `src/dashboard/server.ts` 和 `src/dashboard/routes/index.ts`

**问题**:
- 所有 REST API 端点完全公开，无需认证
- WebSocket 连接无需任何验证
- 任何人都可以：
  - 查看所有迭代记录
  - 修改项目配置
  - 删除数据
  - 控制系统（通过 WebSocket）

**当前代码**:
```typescript
// src/dashboard/routes/index.ts
fastify.get('/iterations', async (request, reply) => {
  // ❌ 无认证检查
  const result = iterationService.getList(options);
  return reply.send(result);
});

fastify.delete('/iterations/:id', async (request, reply) => {
  // ❌ 任何人都可以删除
  const deleted = iterationService.delete(parseInt(id));
  return reply.code(204).send();
});
```

**修复建议**:
```typescript
// 1. 添加认证中间件
// src/dashboard/middleware/auth.ts
import { FastifyRequest } from 'fastify';

interface AuthenticatedRequest extends FastifyRequest {
  user?: {
    id: string;
    role: 'admin' | 'viewer' | 'operator';
  };
}

export async function authenticate(
  request: AuthenticatedRequest,
  reply: any
) {
  const token = request.headers.authorization?.replace('Bearer ', '');

  if (!token) {
    return reply.code(401).send({
      success: false,
      error: { message: 'Missing authentication token', code: 'UNAUTHORIZED' }
    });
  }

  try {
    // 使用 JWT 验证
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    request.user = decoded;
  } catch (error) {
    return reply.code(401).send({
      success: false,
      error: { message: 'Invalid token', code: 'INVALID_TOKEN' }
    });
  }
}

export function authorize(...roles: string[]) {
  return async (request: AuthenticatedRequest, reply: any) => {
    if (!request.user || !roles.includes(request.user.role)) {
      return reply.code(403).send({
        success: false,
        error: { message: 'Insufficient permissions', code: 'FORBIDDEN' }
      });
    }
  };
}

// 2. 应用到路由
fastify.register(async function (fastify) {
  // 公开端点
  fastify.get('/health', async (request, reply) => {
    return reply.send({ status: 'ok' });
  });

  // 需要认证的端点
