```typescript
/**
 * 认证中间件
 */
import { FastifyRequest, FastifyReply } from 'fastify';

const API_KEY_HEADER = 'x-api-key';
const API_KEY_QUERY = 'api_key';

/**
 * 验证 API Key
 */
export function validateApiKey(
  request: FastifyRequest,
  reply: FastifyReply,
  done: () => void
): void {
  const configApiKey = process.env.DASHBOARD_API_KEY;

  // 如果未配置 API Key，跳过验证（开发环境）
  if (!configApiKey) {
    return done();
  }

  // 从 Header 或 Query 获取 API Key
  const providedKey = (
    request.headers[API_KEY_HEADER] as string ||
    (request.query as any)[API_KEY_QUERY]
  );

  if (!providedKey) {
    return reply.status(401).send({
      success: false,
      error: {
        message: 'API Key required',
        code: 'UNAUTHORIZED'
      }
    });
  }

  if (providedKey !== configApiKey) {
    return reply.status(403).send({
      success: false,
      error: {
        message: 'Invalid API Key',
        code: 'FORBIDDEN'
      }
    });
  }

  done();
}

/**
 * 可选的 WebSocket 认证
 */
export function validateWebSocketApiKey(
  connection: any,
  request: any
): boolean {
  const configApiKey = process.env.DASHBOARD_API_KEY;

  if (!configApiKey) return true;

  const providedKey = (
    request.headers[API_KEY_HEADER] ||
    (request.query && request.query[API_KEY_QUERY])
  );

  return providedKey === configApiKey;
}
```

