  // 为所有 /api 路由添加认证
  server.addHook('onRequest', (request, reply, done) => {
    // 健康检查端点除外
    if (request.url === '/api/health') {
      return done();
    }
    validateApiKey(request, reply, done);
  });

  // ... 其余代码
```

